// Source of truth for the PaperRoute launch video copy: props/paperroute-launch.json
// is GENERATED by this script; edit copy here, never in the JSON (it gets clobbered).
// Telemetry is pulled from props/paperroute-demo.json so the demo act never drifts.
import {readFileSync, writeFileSync} from 'node:fs';
import {fileURLToPath} from 'node:url';
import {dirname, join} from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const demo = JSON.parse(readFileSync(join(root, 'props', 'paperroute-demo.json'), 'utf8'));

const launch = {
  brandId: 'paperroute',
  kicker: 'paperroute.gg',
  headline: 'Put the idle corner to work.',
  demo: {video: demo.video, telemetry: demo.telemetry},
  features: [
    {
      screenshot: 'paperroute/measured.png',
      heading: 'Measured, not estimated',
      lines: [
        'One sponsor in the corner nobody was using',
        'Counts only what is actually on screen',
        'Only while you are at the machine',
      ],
    },
    {
      screenshot: 'paperroute/ledger.png',
      heading: 'An auditable 50/50 ledger',
      lines: [
        'You keep half. The split is fixed.',
        'Balance is a sum of append-only entries',
        'Every constant is public at paperroute.gg/transparency',
      ],
    },
  ],
  cta: 'Measure it at paperroute.gg',
  assets: {
    logoSequence: 'paperroute/logo-reveal',
    logoFrames: 90,
    loopSequence: null,
    loopFrames: 1,
  },
};

writeFileSync(join(root, 'props', 'paperroute-launch.json'), JSON.stringify(launch, null, 2) + '\n');
console.log('wrote props/paperroute-launch.json');
